mapper.select:
SELECT s.id, s.amount, s.payment_method AS paymentMethod, s.sale_date AS saleDate, s.memo, up.name AS memberName, p.name AS productName FROM sale s LEFT JOIN users u ON s.user_id = u.user_id LEFT JOIN user_profiles up ON u.user_id = up.user_id LEFT JOIN product p ON s.product_id = p.id WHERE s.product_type=#{category}
AND s.sale_date BETWEEN DATE_SUB(#{date}, INTERVAL WEEKDAY(#{date}) DAY) AND DATE_ADD(DATE_SUB(#{date}, INTERVAL WEEKDAY(#{date}) DAY), INTERVAL 6 DAY)
AND DATE_FORMAT(s.sale_date, '%Y-%m') = DATE_FORMAT(#{date}, '%Y-%m')
AND s.sale_date=#{date}
ORDER BY s.sale_date DESC, s.id DESC

SELECT COUNT(*) AS total, SUM(CASE WHEN up.gender='남자' THEN 1 ELSE 0 END) AS male, SUM(CASE WHEN up.gender='여자' THEN 1 ELSE 0 END) AS female FROM attendance a JOIN users u ON a.user_id = u.user_id LEFT JOIN user_profiles up ON u.user_id = up.user_id
AND a.attend_date BETWEEN DATE_SUB(#{date}, INTERVAL WEEKDAY(#{date}) DAY) AND DATE_ADD(DATE_SUB(#{date}, INTERVAL WEEKDAY(#{date}) DAY), INTERVAL 6 DAY)
AND DATE_FORMAT(a.attend_date, '%Y-%m') = DATE_FORMAT(#{date}, '%Y-%m')
AND a.attend_date=#{date}
AND a.type=#{type}
